// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 100005

int dp[MAXN][MAXN];
int preorder[MAXN], postorder[MAXN];
int N, K;

int count_trees(int pre_start, int pre_end, int post_start, int post_end) {
    if (pre_start > pre_end) return 1;
    if (dp[pre_start][post_start] != -1) return dp[pre_start][post_start];
    int count = 0;
    for (int i = 0; i < K && pre_start + i < pre_end; i++) {
        int j = post_start;
        while (j < post_end && preorder[pre_start + i] != postorder[j]) j++;
        if (j < post_end) {
            count += (long long)count_trees(pre_start + 1, pre_start + i + 1, post_start, j) * count_trees(pre_start + i + 1, pre_end, j + 1, post_end - 1);
            count %= MOD;
        }
    }
    return dp[pre_start][post_start] = count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        for (int i = 0; i < N; i++) scanf("%d", &preorder[i]);
        for (int i = 0; i < N; i++) scanf("%d", &postorder[i]);
        for (int i = 0; i < N; i++) for (int j = 0; j < N; j++) dp[i][j] = -1;
        printf("%d\n", count_trees(0, N, 0, N - 1));
    }
    return 0;
}

